import{supabase}from '../../../supabase-config.js';async function getAuthToken(){try{const{data:{session}}=await supabase.auth.getSession();return session?.access_token||null;}catch(error){return null;}}export async function isAuthenticated(){const token=await getAuthToken();return token!==null;}async function handleResponse(response){if(!response.ok){const errorData=await response.json().catch(()=>({}));throw new Error(errorData.message||`HTTP ${response.status}: ${response.statusText}`);}if(response.status===204){return null;}return response.json();}export async function fetchWithAuth(url,options={}){const token=await getAuthToken();const headers={'Content-Type': 'application/json',...(token&&{'Authorization': `Bearer ${token}`}),...(options.headers||{})};const response=await fetch(url,{...options,headers});return handleResponse(response);}export async function getJSON(url,params={}){const queryString=new URLSearchParams(params).toString();const fullUrl=queryString ? `${url}?${queryString}` : url;return fetchWithAuth(fullUrl,{method: 'GET'});}export async function postJSON(url,data={}){return fetchWithAuth(url,{method: 'POST',body: JSON.stringify(data)});}export async function putJSON(url,data={}){return fetchWithAuth(url,{method: 'PUT',body: JSON.stringify(data)});}export async function patchJSON(url,data={}){return fetchWithAuth(url,{method: 'PATCH',body: JSON.stringify(data)});}export async function deleteJSON(url){return fetchWithAuth(url,{method: 'DELETE'});}export async function queryTable(table,options={}){try{let query=supabase.from(table).select(options.select||'*');if(options.eq){Object.entries(options.eq).forEach(([key,value])=>{query=query.eq(key,value);});}if(options.order){query=query.order(options.order.column,{ascending: options.order.ascending ?? true});}if(options.limit){query=query.limit(options.limit);}const{data,error}=await query;if(error)throw error;return{data,error: null};}catch(error){return{data: null,error};}}export async function insertIntoTable(table,data){try{const{data: result,error}=await supabase .from(table).insert(data).select();if(error)throw error;return{data: result,error: null};}catch(error){return{data: null,error};}}export async function updateInTable(table,data,condition){try{let query=supabase.from(table).update(data);Object.entries(condition).forEach(([key,value])=>{query=query.eq(key,value);});const{data: result,error}=await query.select();if(error)throw error;return{data: result,error: null};}catch(error){return{data: null,error};}}export async function deleteFromTable(table,condition){try{let query=supabase.from(table).delete();Object.entries(condition).forEach(([key,value])=>{query=query.eq(key,value);});const{data: result,error}=await query;if(error)throw error;return{data: result,error: null};}catch(error){return{data: null,error};}}export function handleApiError(error,context=''){return{success: false,error:{message: error.message||'An unexpected error occurred',code: error.code||'UNKNOWN_ERROR',context}};}export async function withRetry(fn,maxRetries=3,delayMs=1000){let lastError;for(let i=0;i<maxRetries;i++){try{return await fn();}catch(error){lastError=error;if(error.status===400||error.status===401||error.status===403){throw error;}if(i<maxRetries-1){await new Promise(resolve=>setTimeout(resolve,delayMs*(i+1)));}}}throw lastError;}export default{getAuthToken,isAuthenticated,fetchWithAuth,getJSON,postJSON,putJSON,patchJSON,deleteJSON,queryTable,insertIntoTable,updateInTable,deleteFromTable,handleApiError,withRetry};